messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "required": [
    "checks",
    "metadata"
  ],
  "properties": {
    "checks": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "bankInfo",
          "personalInfo",
          "checkInfo"
        ],
        "properties": {
          "bankInfo": {
            "type": "object",
            "required": [
              "bank"
            ],
            "properties": {
              "bank": {
                "enum": [
                  "CHASE",
                  "BANK_OF_AMERICA",
                  "WELLS_FARGO",
                  "CITIBANK",
                  "US_BANK"
                ],
                "type": "enum"
              }
            }
          },
          "checkInfo": {
            "type": "object",
            "required": [
              "date",
              "payee",
              "amount",
              "amountInWords",
              "micr",
              "memo"
            ],
            "properties": {
              "date": {
                "type": "string",
                "description": "Date of the check, formatted as YYYY-MM-DD"
              },
              "memo": {
                "type": "string"
              },
              "micr": {
                "type": "object",
                "required": [
                  "checkNumber",
                  "accountNumber",
                  "routingNumber"
                ],
                "properties": {
                  "checkNumber": {
                    "type": "number",
                    "description": "Check number, usually 4 digits"
                  },
                  "accountNumber": {
                    "type": "number",
                    "description": "Account number, usually 8 - 12 digits"
                  },
                  "routingNumber": {
                    "type": "number",
                    "description": "Routing number, usually 9 digits"
                  }
                }
              },
              "payee": {
                "type": "string"
              },
              "amount": {
                "type": "number"
              },
              "amountInWords": {
                "type": "string",
                "description": "Amount in words, excluding the word 'dollars'"
              }
            }
          },
          "personalInfo": {
            "type": "object",
            "required": [
              "firstName",
              "lastName",
              "address",
              "city",
              "state",
              "zip"
            ],
            "properties": {
              "zip": {
                "type": "string"
              },
              "city": {
                "type": "string"
              },
              "state": {
                "type": "string"
              },
              "address": {
                "type": "string"
              },
              "lastName": {
                "type": "string"
              },
              "firstName": {
                "type": "string"
              }
            }
          }
        }
      }
    }
  }
}
